  test('JSON-LD script tag is stripped from output (security) but metadata may be extracted', () async {
    final result = await H2mBridge.convert('<html><head><title>Article</title><script type="application/ld+json">{"@context":"https://schema.org","@type":"Article","headline":"My Article","author":{"@type":"Person","name":"Jane Doe"},"datePublished":"2024-01-15"}</script></head><body><h1>My Article</h1><p>Article body text.</p></body></html>');
    expect(result.content, isNotNull);
    expect(result.content, contains('My Article'));
    expect(result.content, isNot(contains('application/ld+json')));
    expect(result.content, isNot(contains('@context')));
    expect(result.content, isNot(contains('schema.org')));
  });

